CREATE OR REPLACE FUNCTION GET_DEPARTMENT_BY_COMPLAINT_ID 
(
COMPLAINT_ID IN VARCHAR2
) RETURN VARCHAR2 AS 
DEPARTMENT_ID VARCHAR2(50);
BEGIN
SELECT PROJECT_ID INTO DEPARTMENT_ID FROM PROJECT WHERE OPTION_ONE = (SELECT RECEIP_ID FROM DISTRIBUTION_LIST WHERE SYS_ID = (SELECT MIN(SYS_ID) FROM DISTRIBUTION_LIST WHERE CLIENT_COM_ID = COMPLAINT_ID));
RETURN DEPARTMENT_ID;
END GET_DEPARTMENT_BY_COMPLAINT_ID;

